import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const DEPTS = ['CRM', 'Production', 'Store', 'Commercial', 'AfterSales'];

export default function LoginPage() {
  const [isSignup, setIsSignup] = useState(false);
  const [form, setForm] = useState({ username: '', password: '', role: 'employee', department: '', email: '' });
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [loading, setLoading] = useState(false);
  const { login, signup } = useAuth();
  const navigate = useNavigate();

  const set = (k, v) => setForm(p => ({ ...p, [k]: v }));

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setSuccess('');
    setLoading(true);

    try {
      if (isSignup) {
        console.log("🟡 SIGNUP REQUEST:", form);

        await signup({
          username: form.username.trim(),
          password: form.password.trim(),
          email: form.email.trim(),
          role: form.role,
          departments: form.department ? [form.department] : [],
        });

        console.log("✅ SIGNUP SUCCESS");

        setSuccess('Account created! Please log in.');
        setIsSignup(false);
        setForm(p => ({ ...p, password: '' }));

      } else {
        console.log("🔐 LOGIN REQUEST:", form.username, form.password);

        const user = await login(
          form.username.trim(),
          form.password.trim()
        );

        console.log("✅ LOGIN RESPONSE:", user);

        // ✅ SAFETY CHECK (no functionality change)
        if (!user) {
          throw new Error("User not returned from login");
        }

        console.log("👤 USER ROLE:", user.role);

        navigate(
          user.role === 'manager' || user.role === 'admin'
            ? '/mis'
            : '/dashboard'
        );
      }

    } catch (err) {
      console.error("❌ AUTH ERROR:", err);

      setError(
        err?.response?.data?.message ||
        err?.message ||
        (isSignup ? 'Signup failed' : 'Login failed')
      );

    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{
      minHeight: '100vh',
      display: 'flex',
      background: 'var(--ink)',
      fontFamily: 'var(--font-body)',
    }}>
      {/* Left panel (unchanged) */}
      <div style={{
        flex: 1,
        display: 'flex',
        flexDirection: 'column',
        justifyContent: 'center',
        padding: '60px 80px',
      }}>
        <h1 style={{ color: 'white', fontSize: 40 }}>ManufactureOps</h1>
        <p style={{ color: 'gray' }}>Workflow Management</p>
      </div>

      {/* Right form panel */}
      <div style={{
        width: 420,
        background: 'white',
        padding: '40px',
      }}>
        <h2>{isSignup ? 'Create Account' : 'Login'}</h2>

        {error && <p style={{ color: 'red' }}>{error}</p>}
        {success && <p style={{ color: 'green' }}>{success}</p>}

        <form onSubmit={handleSubmit}>
          {isSignup && (
            <>
              <input
                type="email"
                placeholder="Email"
                value={form.email}
                onChange={e => set('email', e.target.value)}
              />
              <br />
            </>
          )}

          <input
            type="text"
            placeholder="Username"
            value={form.username}
            onChange={e => set('username', e.target.value)}
            required
          />
          <br />

          <input
            type="password"
            placeholder="Password"
            value={form.password}
            onChange={e => set('password', e.target.value)}
            required
          />
          <br />

          {isSignup && (
            <>
              <select value={form.role} onChange={e => set('role', e.target.value)}>
                <option value="employee">Employee</option>
                <option value="manager">Manager</option>
              </select>

              <select value={form.department} onChange={e => set('department', e.target.value)}>
                <option value="">Select Dept</option>
                {DEPTS.map(d => <option key={d}>{d}</option>)}
              </select>
            </>
          )}

          <button type="submit" disabled={loading}>
            {loading
              ? (isSignup ? 'Creating...' : 'Signing in...')
              : (isSignup ? 'Sign Up' : 'Login')}
          </button>
        </form>

        <button onClick={() => {
          setIsSignup(!isSignup);
          setError('');
          setSuccess('');
        }}>
          {isSignup ? 'Go to Login' : 'Go to Signup'}
        </button>
      </div>
    </div>
  );
}
